DataPresentationResults <- if (requireNamespace("jmvcore", quietly=TRUE)) R6::R6Class(
    "DataPresentationResults",
    inherit = jmvcore::Group,
    active = list(
        messages = function() private$.items[["messages"]],
        descriptiveTable = function() private$.items[["descriptiveTable"]],
        plots = function() private$.items[["plots"]]),
    private = list(),
    public=list(
        initialize=function(options) {
            super$initialize(
                options=options,
                name="",
                title="Data Presentation")
            self$add(jmvcore::Preformatted$new(
                options=options,
                name="messages",
                title="Analysis Status",
                visible=FALSE))
            self$add(jmvcore::Table$new(
                options=options,
                name="descriptiveTable",
                title="Descriptive Statistics",
                visible="(showTable)",
                refs=list(
                    "dplyr",
                    "tidyr",
                    "emmeans"),
                clearWith=list(
                    "analysisType",
                    "deps",
                    "group",
                    "rm_vars",
                    "group_long",
                    "cov",
                    "cov_long",
                    "showTable",
                    "tableFormat",
                    "tableTitle",
                    "tableNote",
                    "ciWidth",
                    "intStyle"),
                columns=list(
                    list(
                        `name`="variable", 
                        `title`="Variable", 
                        `type`="text", 
                        `combineBelow`=TRUE),
                    list(
                        `name`="n", 
                        `title`="N", 
                        `type`="integer"),
                    list(
                        `name`="mean", 
                        `title`="M", 
                        `type`="number", 
                        `format`="dp:2"),
                    list(
                        `name`="sd", 
                        `title`="SD", 
                        `type`="number", 
                        `format`="dp:2"),
                    list(
                        `name`="se", 
                        `title`="SE", 
                        `type`="number", 
                        `format`="dp:2"),
                    list(
                        `name`="ci_lower", 
                        `title`="CI Lower", 
                        `type`="number", 
                        `format`="dp:2"),
                    list(
                        `name`="ci_upper", 
                        `title`="CI Upper", 
                        `type`="number", 
                        `format`="dp:2"),
                    list(
                        `name`="median", 
                        `title`="Mdn", 
                        `type`="number", 
                        `format`="dp:2"),
                    list(
                        `name`="min", 
                        `title`="Min", 
                        `type`="number", 
                        `format`="dp:2"),
                    list(
                        `name`="max", 
                        `title`="Max", 
                        `type`="number", 
                        `format`="dp:2"))))
            self$add(jmvcore::Array$new(
                options=options,
                name="plots",
                title="Group Comparison Plot",
                refs=list(
                    "ggplot2",
                    "dplyr",
                    "tidyr"),
                clearWith=list(
                    "analysisType",
                    "deps",
                    "group",
                    "rm_vars",
                    "group_long",
                    "cov",
                    "cov_long",
                    "plotType",
                    "intStyle",
                    "showLines",
                    "errorType",
                    "ciWidth",
                    "showPoints",
                    "themePlot",
                    "colorPalette",
                    "color1",
                    "color2",
                    "color3",
                    "color4",
                    "color5",
                    "color6",
                    "color7",
                    "color8",
                    "titleText",
                    "subtitleText",
                    "xLabel",
                    "yLabel",
                    "xAngle",
                    "legendPosition",
                    "removeGap",
                    "customYAxis",
                    "yMin",
                    "yMax",
                    "yStep",
                    "fontSizeTitle",
                    "fontSizeSubtitle",
                    "fontSizeAxis",
                    "fontSizeAxisTitle",
                    "fontSizeLegend",
                    "lineWidth",
                    "errorLineWidth",
                    "axisLineWidth",
                    "barWidth",
                    "barAlpha",
                    "pointSize",
                    "pointAlpha"),
                template=jmvcore::Image$new(
                    options=options,
                    title="$key",
                    width=600,
                    height=500,
                    requiresData=TRUE,
                    renderFun=".plotGroup")))}))

