                version = c(1,2,0),
                options = options,
                results = DataPresentationResults$new(options=options),
                data = data,
                datasetId = datasetId,
                analysisId = analysisId,
                revision = revision,
                pause = NULL,
                completeWhenFilled = FALSE,
                requiresMissings = FALSE,
                weightsSupport = 'auto')
        }))

#' Data Presentation
#'
#' 
#' @param data .
#' @param analysisType .
#' @param deps .
#' @param group .
#' @param rm_vars .
#' @param group_long .
#' @param cov .
#' @param cov_long .
#' @param plotType .
#' @param intStyle .
#' @param showLines .
#' @param errorType .
#' @param ciWidth .
#' @param showPoints .
#' @param showTable .
#' @param tableFormat .
#' @param tableTitle .
#' @param tableNote .
#' @param themePlot .
#' @param colorPalette .
#' @param color1 .
#' @param color2 .
#' @param color3 .
#' @param color4 .
#' @param color5 .
#' @param color6 .
#' @param color7 .
#' @param color8 .
#' @param titleText .
#' @param subtitleText .
#' @param xLabel .
#' @param yLabel .
#' @param xAngle .
#' @param legendPosition .
#' @param removeGap .
#' @param customYAxis .
#' @param yMin .
#' @param yMax .
#' @param yStep .
#' @param fontSizeTitle .
#' @param fontSizeSubtitle .
#' @param fontSizeAxis .
#' @param fontSizeAxisTitle .
#' @param fontSizeLegend .
#' @param lineWidth .
#' @param errorLineWidth .
#' @param axisLineWidth .
#' @param barWidth .
#' @param barAlpha .
#' @param pointSize .
#' @param pointAlpha .
#' @return A results object containing:
#' \tabular{llllll}{
#'   \code{results$messages} \tab \tab \tab \tab \tab a preformatted \cr
#'   \code{results$descriptiveTable} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$plots} \tab \tab \tab \tab \tab One plot per dependent variable \cr
#' }
#'
#' Tables can be converted to data frames with \code{asDF} or \code{\link{as.data.frame}}. For example:
#'
#' \code{results$descriptiveTable$asDF}
#'
#' \code{as.data.frame(results$descriptiveTable)}
#'
#' @export
DataPresentation <- function(
    data,
    analysisType = "cross_sectional",
    deps,
    group,
    rm_vars,
    group_long,
    cov,
    cov_long,
    plotType = "bar",
    intStyle = "legend",
    showLines = TRUE,
    errorType = "sd",
    ciWidth = 95,
    showPoints = FALSE,
    showTable = TRUE,
    tableFormat = "apa",
    tableTitle = "Table 1. Descriptive statistics by group",
    tableNote = "Note. M = mean; SD = standard deviation; SE = standard error; CI = confidence interval; N = sample size.",
    themePlot = "classic",
    colorPalette = "set1",
    color1 = "none",
    color2 = "none",
    color3 = "none",
    color4 = "none",
    color5 = "none",
    color6 = "none",
    color7 = "none",
    color8 = "none",
    titleText = "",
    subtitleText = "",
    xLabel = "",
    yLabel = "",
    xAngle = 0,
    legendPosition = "right",
    removeGap = FALSE,
    customYAxis = FALSE,
    yMin = 0,
    yMax = 100,
    yStep = 10,
    fontSizeTitle = 14,
    fontSizeSubtitle = 12,
    fontSizeAxis = 11,
    fontSizeAxisTitle = 12,
    fontSizeLegend = 10,
    lineWidth = 0.8,
    errorLineWidth = 0.8,
    axisLineWidth = 0.8,
    barWidth = 0.7,
    barAlpha = 1,
    pointSize = 2,
    pointAlpha = 0.5) {

    if ( ! requireNamespace("jmvcore", quietly=TRUE))
        stop("DataPresentation requires jmvcore to be installed (restart may be required)")

    if ( ! missing(deps)) deps <- jmvcore::resolveQuo(jmvcore::enquo(deps))
    if ( ! missing(group)) group <- jmvcore::resolveQuo(jmvcore::enquo(group))
    if ( ! missing(rm_vars)) rm_vars <- jmvcore::resolveQuo(jmvcore::enquo(rm_vars))
    if ( ! missing(group_long)) group_long <- jmvcore::resolveQuo(jmvcore::enquo(group_long))
    if ( ! missing(cov)) cov <- jmvcore::resolveQuo(jmvcore::enquo(cov))
    if ( ! missing(cov_long)) cov_long <- jmvcore::resolveQuo(jmvcore::enquo(cov_long))
    if (missing(data))
        data <- jmvcore::marshalData(
            parent.frame(),
            `if`( ! missing(deps), deps, NULL),
            `if`( ! missing(group), group, NULL),
            `if`( ! missing(rm_vars), rm_vars, NULL),
            `if`( ! missing(group_long), group_long, NULL),
            `if`( ! missing(cov), cov, NULL),
            `if`( ! missing(cov_long), cov_long, NULL))

    for (v in group) if (v %in% names(data)) data[[v]] <- as.factor(data[[v]])
    for (v in group_long) if (v %in% names(data)) data[[v]] <- as.factor(data[[v]])

    options <- DataPresentationOptions$new(
        analysisType = analysisType,
        deps = deps,
        group = group,
        rm_vars = rm_vars,
        group_long = group_long,
        cov = cov,
        cov_long = cov_long,
        plotType = plotType,
        intStyle = intStyle,
        showLines = showLines,
        errorType = errorType,
        ciWidth = ciWidth,
        showPoints = showPoints,
        showTable = showTable,
        tableFormat = tableFormat,
        tableTitle = tableTitle,
        tableNote = tableNote,
        themePlot = themePlot,
        colorPalette = colorPalette,
        color1 = color1,
        color2 = color2,
        color3 = color3,
        color4 = color4,
        color5 = color5,
        color6 = color6,
        color7 = color7,
        color8 = color8,
        titleText = titleText,
        subtitleText = subtitleText,
        xLabel = xLabel,
        yLabel = yLabel,
        xAngle = xAngle,
        legendPosition = legendPosition,
        removeGap = removeGap,
        customYAxis = customYAxis,
        yMin = yMin,
        yMax = yMax,
        yStep = yStep,
        fontSizeTitle = fontSizeTitle,
        fontSizeSubtitle = fontSizeSubtitle,
        fontSizeAxis = fontSizeAxis,
        fontSizeAxisTitle = fontSizeAxisTitle,
        fontSizeLegend = fontSizeLegend,
        lineWidth = lineWidth,
        errorLineWidth = errorLineWidth,
        axisLineWidth = axisLineWidth,
        barWidth = barWidth,
        barAlpha = barAlpha,
        pointSize = pointSize,
        pointAlpha = pointAlpha)

    analysis <- DataPresentationClass$new(
        options = options,
        data = data)

    analysis$run()

    analysis$results
}

